import type { Belt, CommandDefinition } from '@belt/core';
import { Box, Text, useApp, useInput } from 'ink';
import Spinner from 'ink-spinner';
import type React from 'react';
import { useEffect, useState } from 'react';

interface AppProps {
  belt: Belt;
}

type View = 'menu' | 'running' | 'results';

interface ResultDisplay {
  success: boolean;
  errorCount: number;
  warningCount: number;
  duration: number;
}

export function App({ belt }: AppProps): React.ReactElement {
  const { exit } = useApp();
  const [view, setView] = useState<View>('menu');
  const [commands, setCommands] = useState<CommandDefinition[]>([]);
  const [selectedIndex, setSelectedIndex] = useState(0);
  const [currentCommand, setCurrentCommand] = useState('');
  const [results, setResults] = useState<ResultDisplay | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    belt.initialize().then(() => setCommands(belt.getCommands()));
  }, [belt]);

  useInput((input, key) => {
    if (input === 'q' || (key.ctrl && input === 'c')) {
      exit();
      return;
    }

    if (view === 'menu') {
      if (key.upArrow) {
        setSelectedIndex((i) => (i > 0 ? i - 1 : commands.length - 1));
      } else if (key.downArrow) {
        setSelectedIndex((i) => (i < commands.length - 1 ? i + 1 : 0));
      } else if (key.return && commands[selectedIndex]) {
        runCommand(commands[selectedIndex]);
      }
    } else if (view === 'results' && (key.return || key.escape)) {
      setView('menu');
      setResults(null);
      setError(null);
    }
  });

  const runCommand = async (command: CommandDefinition) => {
    setView('running');
    setCurrentCommand(command.name);
    setError(null);

    try {
      const checkResults = await belt.check();
      const totalErrors = checkResults.reduce((sum, r) => sum + r.errorCount, 0);
      const totalWarnings = checkResults.reduce((sum, r) => sum + r.warningCount, 0);
      const totalDuration = checkResults.reduce((sum, r) => sum + r.duration, 0);

      setResults({
        success: totalErrors === 0,
        errorCount: totalErrors,
        warningCount: totalWarnings,
        duration: totalDuration,
      });
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Unknown error');
    }

    setView('results');
  };

  return (
    <Box flexDirection="column" padding={1}>
      <Box marginBottom={1}>
        <Text bold color="cyan">
          Belt
        </Text>
        <Text color="gray"> — Developer Toolkit</Text>
      </Box>

      {view === 'menu' && <Menu commands={commands} selectedIndex={selectedIndex} />}
      {view === 'running' && <Running commandName={currentCommand} />}
      {view === 'results' && <Results result={results} error={error} />}

      <Box marginTop={1} borderStyle="single" borderColor="gray" paddingX={1}>
        <Text color="gray" dimColor>
          {view === 'menu' && '↑↓ Navigate • Enter Select • q Quit'}
          {view === 'running' && 'Running...'}
          {view === 'results' && 'Enter Back • q Quit'}
        </Text>
      </Box>
    </Box>
  );
}

function Menu({
  commands,
  selectedIndex,
}: {
  commands: CommandDefinition[];
  selectedIndex: number;
}) {
  if (commands.length === 0) {
    return <Text color="gray">Loading commands...</Text>;
  }

  return (
    <Box flexDirection="column">
      <Text color="gray" dimColor>
        Select a command:
      </Text>
      <Box flexDirection="column" marginTop={1}>
        {commands.map((cmd, index) => (
          <Box key={cmd.id}>
            <Text color={index === selectedIndex ? 'cyan' : 'white'}>
              {index === selectedIndex ? '❯ ' : '  '}
              {cmd.name}
            </Text>
            <Text color="gray" dimColor>
              {' '}
              — {cmd.description}
            </Text>
          </Box>
        ))}
      </Box>
    </Box>
  );
}

function Running({ commandName }: { commandName: string }) {
  return (
    <Box>
      <Text color="cyan">
        <Spinner type="dots" />
      </Text>
      <Text> Running {commandName}...</Text>
    </Box>
  );
}

function Results({ result, error }: { result: ResultDisplay | null; error: string | null }) {
  if (error) {
    return <Text color="red">✖ Error: {error}</Text>;
  }

  if (!result) {
    return <Text color="gray">No results</Text>;
  }

  return (
    <Box flexDirection="column">
      {result.success ? (
        <Text color="green">✓ All checks passed</Text>
      ) : (
        <Text color="red">✖ {result.errorCount} errors found</Text>
      )}
      {result.warningCount > 0 && <Text color="yellow">⚠ {result.warningCount} warnings</Text>}
      <Text color="gray" dimColor>
        Completed in {result.duration}ms
      </Text>
    </Box>
  );
}

