     1→import { createBelt } from '@belt/core';
     2→import { syncTypesPlugin } from '@belt/plugin-sync-types';
     3→import { typecheckPlugin } from '@belt/plugin-typecheck';
     4→import { render } from 'ink';
     5→import meow from 'meow';
     6→import React from 'react';
     7→import { App } from './app.js';
     8→
     9→const help = `
    10→  Usage
    11→    $ belt [command] [options]
    12→
    13→  Commands
    14→    check        Run all quality checks
    15→    typecheck    Run TypeScript type checking
    16→    sync-types   Generate type declarations from external project
    17→    ui           Launch interactive UI (default)
    18→
    19→  Options
    20→    --help       Show this help
    21→    --version    Show version
    22→    --verbose    Enable verbose output
    23→    --cwd        Set working directory
    24→    --source     Source project path (for sync-types)
    25→    --pattern    Import pattern to match (for sync-types, default: ~/**)
    26→
    27→  Examples
    28→    $ belt check
    29→    $ belt typecheck
    30→    $ belt sync-types --source ../appSemPararv3
    31→    $ belt sync-types --source ../appSemPararv3 --pattern "@semparar/**"
    32→    $ belt
    33→`;
    34→
    35→export async function runCli(): Promise<void> {
    36→  const cli = meow(help, {
    37→    importMeta: import.meta,
    38→    flags: {
    39→      verbose: { type: 'boolean', default: false },
    40→      cwd: { type: 'string', default: process.cwd() },
    41→      source: { type: 'string' },
    42→      pattern: { type: 'string' },
    43→    },
    44→  });
    45→
    46→  const [command] = cli.input;
    47→  const { verbose, cwd, source, pattern } = cli.flags;
    48→
    49→  const belt = createBelt({ rootDir: cwd, verbose });
    50→  belt.use(typecheckPlugin());
    51→
    52→  if (source) {
    53→    belt.use(
    54→      syncTypesPlugin({
    55→        sourceProject: source,
    56→        importPatterns: pattern ? [pattern] : undefined,
    57→      }),
    58→    );
    59→  }
    60→
    61→  switch (command) {
    62→    case 'check': {
    63→      await belt.initialize();
    64→      const results = await belt.check();
    65→
    66→      const totalErrors = results.reduce((sum, r) => sum + r.errorCount, 0);
    67→      const totalWarnings = results.reduce((sum, r) => sum + r.warningCount, 0);
    68→
    69→      if (totalErrors > 0) {
    70→        console.log(`\n\x1b[31m✖ ${totalErrors} errors, ${totalWarnings} warnings\x1b[0m\n`);
